                  </div>
                  <div className="space-y-3">
                    <h3 className="text-lg font-bold text-white flex items-center gap-2">
                      <span className="w-1.5 h-1.5 rounded-full bg-indigo-400" />
                      حكمة عملية
                    </h3>
                    <p className="text-gray-400 leading-relaxed text-sm md:text-base">
                      {state.currentMessage.wisdom}
                    </p>
                  </div>
                </div>
              </div>
            </div>

            <div className="mt-10 flex flex-wrap items-center justify-center gap-4">
              <button 
                onClick={getMessage}
                className="flex items-center gap-2 px-8 py-4 bg-white/10 hover:bg-white/20 rounded-2xl transition-all border border-white/5 active:scale-95"
              >
                <RefreshCw className="w-5 h-5 text-amber-400" />
                <span className="font-semibold">آية أخرى</span>
              </button>

              <button 
                onClick={shareContent}
                className="flex items-center gap-2 px-8 py-4 bg-indigo-600 hover:bg-indigo-500 rounded-2xl transition-all shadow-lg shadow-indigo-600/20 active:scale-95"
              >
                <Share2 className="w-5 h-5" />
                <span className="font-semibold">مشاركة الرسالة</span>
              </button>
            </div>

            <p className="mt-12 text-gray-500 text-sm">
              "قد تكون هذه الآية هي ما تحتاجه لتبدأ يومك بسكينة"
            </p>
          </div>
        )}
      </main>

      {/* Footer */}
      <footer className="relative z-10 p-8 text-center text-gray-600 text-xs">
        <p>© {new Date().getFullYear()} آية لك - منصة روحانية إيمانية</p>
      </footer>

      <style>{`
        @keyframes fade-in {
          from { opacity: 0; transform: translateY(20px); }
          to { opacity: 1; transform: translateY(0); }
        }
        @keyframes slide-up {
          from { opacity: 0; transform: translateY(40px) scale(0.95); }
          to { opacity: 1; transform: translateY(0) scale(1); }
        }
        .animate-fade-in {
          animation: fade-in 1s ease-out forwards;
        }
        .animate-slide-up {
          animation: slide-up 0.8s cubic-bezier(0.16, 1, 0.3, 1) forwards;
        }
      `}</style>
    </div>
  );
};

export default App;

