          // تحميل الصورة إذا كانت المشاركة غير مدعومة
          const url = URL.createObjectURL(blob);
          const a = document.createElement('a');
          a.href = url;
          a.download = `ayah-${state.currentMessage?.surah}.png`;
          a.click();
          URL.revokeObjectURL(url);
          alert("تم تجهيز صورة الرسالة للتحميل!");
        }
      } catch (err) {
        console.error("Error sharing:", err);
      } finally {
        setIsGenerating(false);
      }
    });
  };

