import React, { useState, useCallback, useRef } from 'react';
import Background from './components/Background';
import FloatingHearts from './components/FloatingHearts';
import { LightRays, SparklesParticles } from './components/SpiritualEffects';
import { QuranicMessage, AppState, Mood } from './types';
import { verses } from './data/verses';
import { Share2, RefreshCw, Volume2, VolumeX, Sparkles, Layout, Info, Copy, Check, Download } from 'lucide-react';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    view: 'home',
    currentMessage: null,
    settings: {
      quietMode: false,
      minimalEffects: false
    }
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [copied, setCopied] = useState(false);

  // Transition to Result
  const getMessage = useCallback(() => {
    setState(prev => ({ ...prev, view: 'loading' }));
    setCopied(false);

    const randomIdx = Math.floor(Math.random() * verses.length);
    const selected = verses[randomIdx];

    setTimeout(() => {
      setState(prev => ({ 
        ...prev, 
        view: 'result', 
        currentMessage: selected 
      }));
    }, 2500);
  }, []);

  const toggleQuiet = () => setState(s => ({ 
    ...s, settings: { ...s.settings, quietMode: !s.settings.quietMode } 
  }));

  const toggleMinimal = () => setState(s => ({ 
    ...s, settings: { ...s.settings, minimalEffects: !s.settings.minimalEffects } 
  }));

  const goHome = () => setState(s => ({ ...s, view: 'home', currentMessage: null }));

  // وظيفة تحميل الصورة كملف
  const downloadImage = (blob: Blob, filename: string) => {
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    setTimeout(() => URL.revokeObjectURL(url), 100);
  };

  // وظيفة توليد الصورة للمشاركة
  const generateShareImage = async () => {
    if (!state.currentMessage) return;
    setIsGenerating(true);

    try {
      // التأكد من تحميل الخطوط لضمان ظهور النص بشكل جميل في الصورة
      await document.fonts.ready;

      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) throw new Error("Canvas context not available");

      // إعدادات القياس (1080x1080)
      canvas.width = 1080;
      canvas.height = 1080;

      // 1. رسم الخلفية
      const gradient = ctx.createLinearGradient(0, 0, 0, 1080);
      gradient.addColorStop(0, '#020617');
      gradient.addColorStop(0.5, '#0f172a');
      gradient.addColorStop(1, '#1e1b4b');
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, 1080, 1080);

      // 2. رسم نجوم
      ctx.fillStyle = 'rgba(255, 255, 255, 0.4)';
      for (let i = 0; i < 150; i++) {
        ctx.beginPath();
        ctx.arc(Math.random() * 1080, Math.random() * 1080, Math.random() * 1.5, 0, Math.PI * 2);
        ctx.fill();
      }

      // 3. توهج خلفي
      const radialGlow = ctx.createRadialGradient(540, 540, 50, 540, 540, 450);
      radialGlow.addColorStop(0, 'rgba(245, 158, 11, 0.12)');
      radialGlow.addColorStop(1, 'rgba(245, 158, 11, 0)');
      ctx.fillStyle = radialGlow;
      ctx.fillRect(0, 0, 1080, 1080);

      // 4. رسم النص (الآية)
      ctx.direction = 'rtl';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';

      ctx.fillStyle = '#fffbeb';
      // محاولة استخدام خطوط عربية محددة أو الخط الافتراضي كبديل
      ctx.font = 'bold 64px "Amiri", serif';

      const ayahText = `"${state.currentMessage.ayah}"`;
      const words = ayahText.split(' ');
      let line = '';
      let y = 480;
      const maxWidth = 850;
      const lineHeight = 110;

      for (let n = 0; n < words.length; n++) {
        let testLine = line + words[n] + ' ';
        let metrics = ctx.measureText(testLine);
        if (metrics.width > maxWidth && n > 0) {
          ctx.fillText(line, 540, y);
          line = words[n] + ' ';
          y += lineHeight;
        } else {
          line = testLine;
        }
      }
      ctx.fillText(line, 540, y);

      // 5. رسم المعلومات الجانبية
      ctx.font = 'normal 38px "Cairo", sans-serif';
      ctx.fillStyle = '#fbbf24';
      ctx.fillText(`سورة ${state.currentMessage.surah} | آية ${state.currentMessage.ayahNumber}`, 540, y + 130);

      ctx.font = 'bold 34px "Cairo", sans-serif';
      ctx.globalAlpha = 0.5;
      ctx.fillText(`رسالة ${state.currentMessage.mood}`, 540, 280);
      ctx.globalAlpha = 1.0;

      // 6. الهوية
      ctx.font = 'bold 44px "Cairo", sans-serif';
      ctx.fillStyle = '#fbbf24';
      ctx.fillText('آية لك', 540, 940);
      ctx.font = 'normal 26px "Cairo", sans-serif';
      ctx.fillStyle = '#94a3b8';
      ctx.fillText('تلقيت هذه الرسالة اليوم من القرآن الكريم', 540, 1000);

      const fileName = `ayah-${state.currentMessage?.surah}-${Date.now()}.png`;

      canvas.toBlob(async (blob) => {
        if (!blob) {
          setIsGenerating(false);
          return;
        }

        const file = new File([blob], fileName, { type: 'image/png' });

        try {
          // التحقق من دعم المشاركة ونوع الملف
          if (navigator.share && navigator.canShare && navigator.canShare({ files: [file] })) {
            await navigator.share({
              files: [file],
              title: 'آية لك',
              text: `تلقيت رسالة طمأنينة من القرآن الكريم: ${state.currentMessage?.ayah}`
            });
          } else {
            // التحميل المباشر في حال عدم الدعم
            downloadImage(blob, fileName);
          }
        } catch (err: any) {
          // تجاهل الخطأ في حال قيام المستخدم بإلغاء نافذة المشاركة (AbortError)
          if (err.name === 'AbortError') {
            console.log('User cancelled share');
          } else {
            // في أي حالة فشل أخرى، نقوم بتحميل الصورة تلقائياً لضمان عدم ضياع التجربة
            console.error("Share failed:", err);
            downloadImage(blob, fileName);
          }
        } finally {
          setIsGenerating(false);
        }
      }, 'image/png');

    } catch (error) {
      console.error("Image generation failed:", error);
      setIsGenerating(false);
      alert("عذراً، حدث خطأ أثناء تجهيز الصورة. يمكنك نسخ النص بدلاً من ذلك.");
    }
  };

  const copyToClipboard = () => {
    if (state.currentMessage) {
      const text = `"${state.currentMessage.ayah}"\nسورة ${state.currentMessage.surah} - آية ${state.currentMessage.ayahNumber}\n\nتلقيت هذه الرسالة اليوم من تطبيق آية لك.`;
      navigator.clipboard.writeText(text).then(() => {
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
      });
    }
  };

  return (
    <div className="relative min-h-screen text-white overflow-hidden flex flex-col transition-all duration-700">
      <Background minimal={state.settings.minimalEffects} />

      {/* Top Navbar */}
      <nav className="relative z-10 p-6 flex justify-between items-center w-full max-w-5xl mx-auto">
        <div className="flex items-center gap-2 cursor-pointer" onClick={goHome}>
          <div className="w-10 h-10 bg-gradient-to-tr from-amber-400 to-amber-200 rounded-xl flex items-center justify-center shadow-lg shadow-amber-400/20">
            <Sparkles className="text-amber-900 w-6 h-6" />
          </div>
          <h1 className="text-2xl font-bold bg-clip-text text-transparent bg-gradient-to-l from-amber-200 to-amber-400 tracking-wide">
            آية لك
          </h1>
        </div>

        <div className="flex gap-4">
          <button 
            onClick={toggleQuiet}
            className="p-2 hover:bg-white/10 rounded-full transition-colors"
            title={state.settings.quietMode ? "تفعيل الصوت" : "كتم الصوت"}
          >
            {state.settings.quietMode ? <VolumeX className="w-5 h-5 opacity-60" /> : <Volume2 className="w-5 h-5 opacity-80" />}
          </button>
          <button 
            onClick={toggleMinimal}
            className="p-2 hover:bg-white/10 rounded-full transition-colors"
            title="تبديل الوضع"
          >
            <Layout className={`w-5 h-5 ${state.settings.minimalEffects ? 'opacity-40' : 'opacity-80'}`} />
          </button>
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="relative z-10 flex-grow flex flex-col items-center justify-center p-6 text-center">

        {state.view === 'home' && (
          <div className="max-w-2xl animate-fade-in">
            <FloatingHearts />
            <h2 className="text-3xl md:text-5xl font-bold mb-4 bg-clip-text text-transparent bg-gradient-to-b from-white to-gray-400">
              قد تكون هذه هي الرسالة التي تحتاجها الآن
            </h2>
            <p className="text-gray-400 text-lg mb-10 max-w-md mx-auto leading-relaxed">
              منصة روحانية تقدم لك رسالة من القرآن في اللحظة التي تحتاجها، لتكون مصدر طمأنينة وإلهام في حياتك اليومية.
            </p>

            <button
              onClick={getMessage}
              className="group relative px-10 py-5 bg-gradient-to-r from-amber-500 to-amber-400 text-amber-950 font-bold text-xl rounded-full shadow-[0_0_30px_rgba(245,158,11,0.4)] hover:shadow-[0_0_50px_rgba(245,158,11,0.6)] transform hover:-translate-y-1 transition-all duration-300 overflow-hidden"
            >
